from dataclasses import dataclass
from enum import Enum

class PatchKind(str, Enum):
    SECURITY_CRITICAL = "security_critical"   # CVE CRITICAL, 24h deadline
    SECURITY_HIGH     = "security_high"       # CVE HIGH, 72h deadline
    DEPENDENCY_BUMP   = "dependency_bump"     # routine version update
    FEATURE_PATCH     = "feature_patch"       # new API surface, no breaking changes
    BUG_FIX           = "bug_fix"             # correctness fix, no interface change

@dataclass
class ValidationPlan:
    patch_kind: PatchKind
    touches_inference_path: bool

    def stages_required(self) -> list[str]:
        stages = ["unit_tests"]

        if self.patch_kind != PatchKind.SECURITY_CRITICAL:
            stages.append("integration_tests")

        if self.touches_inference_path:
            stages.append("ai_quality_check")

        if self.patch_kind not in (PatchKind.SECURITY_CRITICAL,):
            stages.append("staging_e2e")

        stages.append("production_monitoring")
        return stages

    def monitoring_window_minutes(self) -> int:
        if self.patch_kind == PatchKind.SECURITY_CRITICAL:
            return 30
        if self.patch_kind == PatchKind.SECURITY_HIGH:
            return 45
        return 60

    def can_deploy_on_fail(self, stage: str) -> bool:
        # Only the production monitoring stage can be 'failed' after the
        # fact — all pre-production stages are blocking.
        return stage == "production_monitoring"

from dataclasses import dataclass, field
from collections import deque

@dataclass
class TestFlakinesTracker:
    test_id: str
    history: deque = field(default_factory=lambda: deque(maxlen=20))

    def record(self, passed: bool) -> None:
        self.history.append(passed)

    def flakiness_rate(self) -> float:
        if len(self.history) < 5:
            return 0.0   # insufficient data
        passes = sum(self.history)
        return 1.0 - (passes / len(self.history))

    def should_quarantine(self) -> bool:
        # Quarantine if > 10% failure rate over last 20 runs
        return self.flakiness_rate() > 0.10

    def quarantine_action(self) -> str:
        if not self.should_quarantine():
            return "none"
        rate = self.flakiness_rate()
        if rate > 0.30:
            # Too unreliable to run at all — remove from blocking gates
            return "remove_from_blocking_gates"
        # Mark as non-blocking but keep in pipeline for visibility
        return "downgrade_to_advisory"
